        classOfRec: "I",
        classNote: null,
        levelOfEvidence: "B-NR",
        text: "Facilities caring for acute stroke patients are recommended to develop and adopt care protocols reflecting current clinical guidelines from national and international professional organizations or regulatory agencies.",
