        section: "Other Diagnostic Tests",
        classOfRec: "I",
        classNote: null,
        levelOfEvidence: "C-LD",
        text: "Baseline ECG assessment is recommended in patients with suspected acute stroke but is not recommended to delay initiation of IVT or EVT.",
