        classOfRec: "I",
        classNote: null,
        levelOfEvidence: "C-LD",
        text: "In acute stroke patients with decreased consciousness or bulbar dysfunction, airway support and ventilatory assistance are recommended as needed to maintain airway protection and adequate ventilation and oxygenation.",
